import React, { useState, useEffect } from "react";
import { useParams, Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import API from "../api/axios";
import "../App.css";

const PostPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [post, setPost] = useState(null);
  const [comments, setComments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [newComment, setNewComment] = useState("");

  useEffect(() => {
    const fetchPost = async () => {
      try {
        const res = await API.get(`/posts/${id}`);
        setPost(res.data);

        const commentsRes = await API.get(`/comments/${id}`);
        setComments(commentsRes.data);

      } catch (err) {
        setError("Post not found or error loading post");
      } finally {
        setLoading(false);
      }
    };

    fetchPost();
  }, [id]);

  const handleAddComment = async (e) => {
    e.preventDefault();
    if (!newComment.trim()) return;

    try {
      const res = await API.post(`/comments/${id}`, {
        body: newComment,
      });

      setComments([res.data, ...comments]);
      setNewComment("");
    } catch (err) {
      setError("Failed to add comment");
    }
  };

  // SAFE LOADING
  if (loading) return <div>Loading post...</div>;

  if (error)
    return (
      <div style={{ textAlign: "center", padding: "40px" }}>
        {error}
        <br />
        <button onClick={() => navigate("/")}>Go Home</button>
      </div>
    );

  // SAFE GUARD (IMPORTANT FIX)
  if (!post) return <div>No post found</div>;

  // SAFE OWNER CHECK (FIXED CRASH ISSUE)
  const isOwner =
    user &&
    post &&
    post.author &&
    user._id === post.author._id;

  return (
    <section className="single-post-page">

      <div className="post-header">
        <div className="action-buttons">
          <Link to="/create-post" className="nav-btn">
            New Post
          </Link>

          {isOwner && (
            <>
              <Link to={`/edit-post/${id}`} className="nav-btn">
                Edit Post
              </Link>

              <button className="nav-btn">
                Delete Post
              </button>
            </>
          )}
        </div>
      </div>

      <article className="single-post-card">
        <h2>{post?.title}</h2>
        <div>{post?.body}</div>
      </article>

      {/* SAFE IMAGE */}
      {post?.image && (
        <div className="post-featured-image">
          <img
            src={`http://localhost:5000/uploads/${post.image}`}
            alt="post"
          />
        </div>
      )}

      {/* COMMENTS */}
      <section className="comments-section">
        <h3>Comments ({comments.length})</h3>

        {user && (
          <form onSubmit={handleAddComment}>
            <input
              value={newComment}
              onChange={(e) => setNewComment(e.target.value)}
              placeholder="Add comment..."
            />
            <button type="submit">Post</button>
          </form>
        )}

        {comments.map((c) => (
          <div key={c._id}>
            <strong>{c.author?.name || "User"}</strong>
            <p>{c.body}</p>
          </div>
        ))}
      </section>

    </section>
  );
};

export default PostPage;
